#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        if (n == 2) {
            printf("2 1\n");
        } else {
            printf("2");
            for (int i = 3; i <= n; i++) {
                printf(" %d", i);
            }
            printf(" 1\n");
        }
    }
    return 0;
}

