code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            if (n == 2) {
                System.out.println("2 1");
            } else {
                System.out.print("2");
                for (int i = 3; i <= n; i++) {
                    System.out.print(" " + i);
                }
                System.out.println(" 1");
            }
        }
    }
}

